import re
from pathlib import Path

import pytest

AC_UID = "26a6449a5b99964c"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
CANARY = REPO_ROOT / "scripts" / "canary-verify.sh"


def test_AC_12():
    """
    GIVEN: scripts/canary-verify.sh is read as text
    WHEN:  grep -n '/tmp/' scripts/canary-verify.sh is run
    THEN:  exit code MUST be 1 (no matches); both temp files via mktemp
    """
    assert CANARY.is_file(), f"missing canary-verify.sh: {CANARY}"
    text = CANARY.read_text(encoding="utf-8")

    # /tmp/ must not appear anywhere
    hits = [
        (i + 1, line)
        for i, line in enumerate(text.splitlines())
        if "/tmp/" in line
    ]
    assert not hits, (
        f"canary-verify.sh contains hardcoded /tmp/ paths (must use mktemp -t canary-): {hits}"
    )

    # mktemp -t canary-... pattern must exist
    assert re.search(r"mktemp\s+-t\s+canary-", text), (
        "canary-verify.sh missing required `mktemp -t canary-` invocation"
    )
